fun solve(n: Long, edges: Array<Array<Long>>, k: Long): Long {
    // Sort edges by time in ascending order
    val sortedEdges = edges.sortedBy { it[2] }

    // Union-Find data structure to keep track of connected components
    val parent = Array(n.toInt()) { it.toInt() }
    val rank = Array(n.toInt()) { 0 }

    fun find(x: Int): Int {
        if (parent[x] != x) {
            parent[x] = find(parent[x])
        }
        return parent[x]
    }

    fun union(x: Int, y: Int): Boolean {
        val rootX = find(x)
        val rootY = find(y)
        if (rootX == rootY) return false
        if (rank[rootX] > rank[rootY]) {
            parent[rootY] = rootX
        } else if (rank[rootX] < rank[rootY]) {
            parent[rootX] = rootY
        } else {
            parent[rootY] = rootX
            rank[rootX]++
        }
        return true
    }

    // Initially, all nodes are separate
    var componentCount = n.toInt()

    // Iterate through edges in sorted order
    for (edge in sortedEdges) {
        val u = edge[0].toInt()
        val v = edge[1].toInt()
        val time = edge[2]

        if (union(u, v)) {
            componentCount--
        }

        // Check if we have at least k components
        if (componentCount >= k) {
            return time
        }
    }

    // If we haven't found the answer, return the maximum time (all edges are removed)
    return sortedEdges.lastOrNull()?.let { it[2] } ?: 0L
}
